/// GET /ready — readiness probe for the local process surfaces.
pub async fn ready(State(state): State<SharedState>) -> impl IntoResponse {
    let publisher = state.publisher.health_snapshot();
    let (status, code) = if publisher.configured && publisher.last_error.is_some() {
        ("degraded", StatusCode::SERVICE_UNAVAILABLE)
    } else {
        ("ok", StatusCode::OK)
    };

    (
        code,
        Json(ReadyReport {
            status,
            local: "ok",
            sync: ReadySyncStatus { publisher },
        }),
    )
        .into_response()
}

async fn get_or_create_session(
    client_addr: SocketAddr,
    listen_socket: Arc<UdpSocket>,
    server_addr: SocketAddr,
    obfuscation: WgPacketObfuscation,
    idle_timeout: Duration,
    sessions: Arc<DashMap<SocketAddr, Arc<ShimSession>>>,
    shutdown: CancellationToken,
) -> io::Result<Arc<ShimSession>> {
    // Fast path: session already exists
    if let Some(existing) = sessions.get(&client_addr) {
        return Ok(existing.clone());
    }

    // Create socket outside of lock
    let upstream_socket =
        Arc::new(UdpSocket::bind(SocketAddr::from(([0, 0, 0, 0], 0))).await?);
    upstream_socket.connect(server_addr).await?;
    let new_session = Arc::new(ShimSession::new(upstream_socket));

    // Re-check and insert atomically
    let session = match sessions.entry(client_addr) {
        Entry::Occupied(existing) => {
            // Another task won the race; discard our socket and use theirs
            existing.get().clone()
        }
        Entry::Vacant(vacant) => {
            let session = vacant.insert(new_session).clone();
            tokio::spawn(run_session_receiver(
                client_addr,
                session.clone(),
                listen_socket,
                obfuscation,
                idle_timeout,
                sessions.clone(),
                shutdown,
            ));
            session
        }
    };
    Ok(session)
}

